import React from 'react';
import Navbar from './Navbar';

const Contact: React.FC = () => {
  return (
    <div>
      <Navbar />
      <div className="max-w-6xl mx-auto px-4 py-6">
        <div className="bg-white rounded-xl shadow-md p-6">
          <h1 className="text-3xl font-bold text-gray-800 mb-4">Contact Us</h1>
          <p className="text-gray-600 mb-4">Feel free to reach out to us with any questions or feedback.</p>
          <form className="space-y-4">
            <input type="text" placeholder="Your Name" className="w-full p-2 border border-gray-300 rounded-lg" />
            <input type="email" placeholder="Your Email" className="w-full p-2 border border-gray-300 rounded-lg" />
            <textarea placeholder="Your Message" className="w-full p-2 border border-gray-300 rounded-lg"></textarea>
            <button type="submit" className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Send Message</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Contact;

